<?php session_start(); include '../includes/db.php'; if(!isset($_SESSION['user_id']) || $_SESSION['role'] !== 'admin'){ header('Location: ../login.php'); exit(); } $result=$conn->query('SELECT * FROM payments ORDER BY created_at DESC'); include '../includes/header.php'; ?>
